#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int K;
        scanf("%d", &K);
        char c;
        int count;
        long long total = 0;
        long long current = 0;
        char prev_c;
        int prev_count;
        for (int i = 0; i < K; i++) {
            scanf(" %c %d", &c, &count);
            total += count;
            long long temp = (count * (count + 1)) / 2;
            current += temp;
            if (i > 0) {
                if (c == prev_c) {
                    current += (count * prev_count);
                }
            }
            prev_c = c;
            prev_count = count;
        }
        printf("%lld\n", current);
    }
    return 0;
}

