import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int K = sc.nextInt();
            char c;
            int count;
            long total = 0;
            long current = 0;
            char prev_c = ' ';
            int prev_count = 0;
            for (int i = 0; i < K; i++) {
                c = sc.next().charAt(0);
                count = sc.nextInt();
                total += count;
                long temp = (count * (count + 1)) / 2;
                current += temp;
                if (i > 0) {
                    if (c == prev_c) {
                        current += (count * prev_count);
                    }
                }
                prev_c = c;
                prev_count = count;
            }
            System.out.println(current);
        }
    }
}

